"""Emission compliance tests for assessor (auto-generated by pact)."""

from assessor.assessor import Assessor


class TestEmissionCompliance:
    """Verify assessor emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_merge_assessments_emits_events(self):
        """Method merge_assessments emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Assessor(event_handler=handler)
        try:
            obj.merge_assessments()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for merge_assessments'
        assert len(completed) >= 1, 'No completed/error event for merge_assessments'
        assert invoked[0].get("pact_key") == "PACT:assessor:merge_assessments"
        assert isinstance(invoked[0].get("input_classification"), list)

