    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Assessor(event_handler=handler)
        try:
            obj.merge_assessments()
        except (TypeError, Exception):
            pass
        try:
            obj._resolve_trust()
        except (TypeError, Exception):
            pass
        try:
            obj._deduplicate_findings()
        except (TypeError, Exception):
            pass
        try:
            obj._compute_decision()
        except (TypeError, Exception):
            pass
        try:
            obj._build_report()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:assessor:"), f"Bad pact_key: {key}"

